#include <iostream>
using namespace std;

void postOrder(int pre[], int in[], int n) {
    if (n == 0) return;
    int root = pre[0];
    int i;
    for (i = 0; i < n; i++) {
        if (in[i] == root) break;
    }
    postOrder(pre + 1, in, i);
    postOrder(pre + i + 1, in + i + 1, n - i - 1);
    cout << root;
    if (n > 1) cout << " ";
}

int main() {
    int n;
    cin >> n;
    int pre[100], in[100];
    for (int i = 0; i < n; i++) cin >> pre[i];
    for (int i = 0; i < n; i++) cin >> in[i];
    postOrder(pre, in, n);
    cout << endl;
    return 0;
}
